import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/launcher-screen.B4Y3DSWp.js";import{t as a}from"./chunks/installing-mods.gZ3xnRXE.js";const o=JSON.parse(`{"title":"Instalando Mods","description":"Um guia passo a passo de como instalar mods para Fabric.","frontmatter":{"title":"Instalando Mods","description":"Um guia passo a passo de como instalar mods para Fabric.","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"pt_br/1.21.1/players/installing-mods.md","filePath":"versions/1.21.1/translated/pt_br/players/installing-mods.md","lastUpdated":1761424914000}`);var s={name:`pt_br/1.21.1/players/installing-mods.md`};function c(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Instalando Mods <a class="header-anchor" href="#h1" aria-label="Permalink to “Instalando Mods”">​</a></h1><p>Este guia o orientará na instalação de mods para Fabric usando o Minecraft Launcher.</p><p>Para launchers de terceiros, você deve consultar suas devidas documentações.</p><h2 id="_1-baixar-o-mod" tabindex="-1">1. Baixar o Mod <a class="header-anchor" href="#_1-baixar-o-mod" aria-label="Permalink to “1. Baixar o Mod”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Você deve baixar mods apenas de fontes que confia. Para mais informações sobre achar mods, veja o guia <a href="./finding-mods">Encontrando Mods Confiáveis</a>.</p></div><p>A maioria dos mods necessitam do Fabric API, que pode ser baixado através do <a href="https://modrinth.com/mod/fabric-api" target="_blank" rel="noreferrer">Modrinth</a> ou <a href="https://curseforge.com/minecraft/mc-mods/fabric-api" target="_blank" rel="noreferrer">CurseForge</a>.</p><p>Ao baixar mods, certifique-se de que:</p><ul><li>Eles funcionam na versão do Minecraft que você quer jogar. Um mod feito para a versão 1.20, por exemplo, pode não funcionar na versão 1.20.2.</li><li>Eles são para o Fabric, não outro mod loader (carregador de mods).</li><li>Eles são feitos para a edição certa do Minecraft (Edição Java).</li></ul><h2 id="_2-mover-o-mod-para-a-pasta-mods" tabindex="-1">2. Mover o Mod para a Pasta <code>mods</code> <a class="header-anchor" href="#_2-mover-o-mod-para-a-pasta-mods" aria-label="Permalink to “2. Mover o Mod para a Pasta mods”">​</a></h2><p>A pasta de mods pode ser encontrada nos seguintes locais para cada sistema operacional.</p><p>Você pode colar esses endereços na barra de endereços do seu navegador de arquivos para rapidamente achar a pasta.</p><div class="vp-code-group"><div class="tabs"><input type="radio" name="group-49" id="tab-50" checked><label data-title="Windows" for="tab-50">Windows</label><input type="radio" name="group-49" id="tab-51"><label data-title="macOS" for="tab-51">macOS</label><input type="radio" name="group-49" id="tab-52"><label data-title="Linux" for="tab-52">Linux</label></div><div class="blocks"><div class="language- active"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>%appdata%\\.minecraft\\mods</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/Library/Application Support/minecraft/mods</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/.minecraft/mods</span></span></code></pre></div></div></div><p>Encontrada a pasta <code>mods</code>, você pode mover os arquivos <code>.jar</code> dos mods para dentro dela.</p><p><img src="/assets/players/installing-mods.png" alt="Mods instalados na pasta de mods" loading="lazy"></p><h2 id="_3-tudo-pronto" tabindex="-1">3. Tudo Pronto! <a class="header-anchor" href="#_3-tudo-pronto" aria-label="Permalink to “3. Tudo Pronto!”">​</a></h2><p>Assim que movidos os mods para a pasta <code>mods</code>, você pode abrir o Minecraft Launcher, selecionar o perfil Fabric através do botão no canto inferior esquerdo e clicar em jogar!</p><p><img src="/assets/players/installing-fabric/launcher-screen.png" alt="Minecraft Launcher com o perfil Fabric selecionado" loading="lazy"></p><h2 id="solucao-de-problemas" tabindex="-1">Solução de Problemas <a class="header-anchor" href="#solucao-de-problemas" aria-label="Permalink to “Solução de Problemas”">​</a></h2><p>Se você encontrar algum problema, sinta-se à vontade para pedir ajuda no <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Discord do Fabric</a> no canal <code>#player-support</code>.</p><p>Você também pode tentar diagnosticar o problema por si mesmo através das páginas de solução de problemas:</p><ul><li><a href="./troubleshooting/crash-reports">Relatórios de Crash</a></li><li><a href="./troubleshooting/uploading-logs">Upload de Logs</a></li></ul>`,21)]])}var l=r(s,[[`render`,c]]);export{o as __pageData,l as default};